export const createTask: CreateTask<{ description: string }, Task> = async ({ description }, context) => {
  const maxPositionTask = await context.entities.Task.findFirst({
    orderBy: { position: 'desc' },
  });
  const position = maxPositionTask ? maxPositionTask.position + 1 : 1;

  return context.entities.Task.create({
    data: { description, position },
  });
};

export const moveTaskUp: MoveTaskUp<{ id: number }, void> = async ({ id }, context) => {
  const task = await context.entities.Task.findUnique({ where: { id } });
  if (!task) throw new Error('Task not found');

  const taskAbove = await context.entities.Task.findFirst({
    where: { position: { lt: task.position } },
    orderBy: { position: 'desc' },
  });

  if (!taskAbove) return; // Already at the top

  await context.entities.Task.update({
    where: { id: task.id },
    data: { position: taskAbove.position },
  });

  await context.entities.Task.update({
    where: { id: taskAbove.id },
    data: { position: task.position },
  });
};

