import React, { useState } from 'react';
import { useQuery, useAction } from 'wasp/client/operations';
import { getTasks, createTask, moveTaskUp } from 'wasp/client/operations';

export const MainPage = () => {
  const { data: tasks, isLoading, error } = useQuery(getTasks);
  const createTaskAction = useAction(createTask);

  const moveTaskUpAction = useAction(moveTaskUp, {
    optimisticUpdates: [
      {
        getQuerySpecifier: () => [getTasks],
        updateQuery: ({ id }, oldTasks) => {
          if (!oldTasks) return oldTasks;
          const index = oldTasks.findIndex(t => t.id === id);
          if (index <= 0) return oldTasks; // Cannot move up

          const newTasks = [...oldTasks];
          // Swap positions
          const tempPos = newTasks[index].position;
          newTasks[index] = { ...newTasks[index], position: newTasks[index - 1].position };
          newTasks[index - 1] = { ...newTasks[index - 1], position: tempPos };

          // Sort by position to maintain order
          return newTasks.sort((a, b) => a.position - b.position);
        }
      }
    ]
  });

  const [description, setDescription] = useState('');

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!description.trim()) return;
    await createTaskAction({ description });
    setDescription('');
  };

  if (isLoading) return <div>Loading...</div>;
  if (error) return <div>Error: {error.message}</div>;

  return (
    <div style={{ padding: '20px' }}>
      <h1>Tasks</h1>
      <form onSubmit={handleCreate}>
        <input 
          type="text" 
          value={description} 
          onChange={e => setDescription(e.target.value)} 
          placeholder="New Task"
        />
        <button type="submit">Add Task</button>
      </form>

      <ul>
        {tasks?.map((task, index) => (
          <li key={task.id} style={{ display: 'flex', gap: '10px', margin: '10px 0' }}>
            <span>{task.description} (Pos: {task.position})</span>
            {index > 0 && (
              <button onClick={() => moveTaskUpAction({ id: task.id })}>
                Move Up
              </button>
            )}
          </li>
        ))}
      </ul>
    </div>
  );
};

